DELETE FROM tb_task_strategy t
WHERE t.id IN

    #{id}

mapper.select:
SELECT 
FROM tb_task_strategy t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.task_id = #{taskId}


    AND t.strategy_type = #{strategyType}


    AND t.strategy_expression = #{strategyExpression}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC
